func TestAuthLoginDiscoverability(t *testing.T) {
	t.Parallel()

	root := RootCmd()
	for _, args := range [][]string{
		{"auth", "login"},
		{"login"},
	} {
		cmd, remaining, err := root.Find(args)
		if err != nil {
			t.Fatalf("Find(%v) returned error: %v", args, err)
		}
		if len(remaining) != 0 {
			t.Fatalf("Find(%v) returned remaining args %v", args, remaining)
		}
		if cmd == nil || cmd.Name() != "login" {
			t.Fatalf("Find(%v) = %v, want login command", args, cmd)
		}
	}
}

func TestAuthSetupPointsToAuthLogin(t *testing.T) {
	t.Parallel()

	root := RootCmd()
	var out bytes.Buffer
	root.SetOut(&out)
	root.SetErr(&bytes.Buffer{})
	root.SetArgs([]string{"auth", "setup"})

	if err := root.Execute(); err != nil {
		t.Fatalf("auth setup returned error: %v", err)
	}
	got := out.String()
	if !strings.Contains(got, "amazon-ads-pp-cli auth login") {
		t.Fatalf("auth setup output = %q, want auth login guidance", got)
	}
	if !strings.Contains(got, defaultOAuthCallbackURL) {
		t.Fatalf("auth setup output = %q, want callback URL guidance", got)
	}
	if !strings.Contains(got, "amazon-ads-pp-cli auth login --port 8085") {
		t.Fatalf("auth setup output = %q, want explicit auth login port", got)
	}
	if strings.Contains(got, "amazon-ads-pp-cli login") {
		t.Fatalf("auth setup output still points at top-level login alias: %q", got)
	}
}

func TestMaybeSelectAmazonAdsProfileAutoSelectsSingleProfile(t *testing.T) {
	clearAmazonAdsEnvForCLITest(t)
	var profileCalls int
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		profileCalls++
		if r.URL.Path != "/v2/profiles" {
			t.Fatalf("path = %q, want /v2/profiles", r.URL.Path)
		}
		if got := r.Header.Get("Authorization"); got != "Bearer access-token" {
			t.Fatalf("Authorization = %q, want Bearer access-token", got)
		}
		if got := r.Header.Get("Amazon-Advertising-API-ClientId"); got != "client-id" {
			t.Fatalf("client ID header = %q, want client-id", got)
		}
		w.Header().Set("Content-Type", "application/json")
		_, _ = w.Write([]byte(`[{"profileId":1234567890123456789,"countryCode":"US","accountInfo":{"name":"Brand Store","type":"seller"}}]`))
	}))
	defer srv.Close()

	configDir := filepath.Join(t.TempDir(), ".config", "amazon-ads-pp-cli")
	if err := os.MkdirAll(configDir, 0o700); err != nil {
		t.Fatalf("mkdir config dir: %v", err)
	}
	cfg := &config.Config{
		Path:    filepath.Join(configDir, "config.toml"),
		BaseURL: srv.URL,
	}
	root := RootCmd()
	var errOut bytes.Buffer
	root.SetErr(&errOut)

	if err := maybeSelectAmazonAdsProfile(root, &rootFlags{}, cfg, "client-id", "access-token"); err != nil {
		t.Fatalf("maybeSelectAmazonAdsProfile returned error: %v", err)
	}
	if profileCalls != 1 {
		t.Fatalf("profileCalls = %d, want 1; cfg=%+v stderr=%q", profileCalls, cfg, errOut.String())
	}
	if cfg.AmazonAdsProfileId != "1234567890123456789" {
		t.Fatalf("selected profile = %q, want 1234567890123456789", cfg.AmazonAdsProfileId)
	}
	data, err := os.ReadFile(filepath.Join(configDir, ".env"))
	if err != nil {
		t.Fatalf("read .env: %v", err)
	}
	if got := string(data); !strings.Contains(got, "AMAZON_ADS_PROFILE_ID=1234567890123456789") {
		t.Fatalf(".env did not persist selected profile:\n%s", got)
	}
	if !strings.Contains(errOut.String(), "Selected advertising profile 1234567890123456789") {
		t.Fatalf("stderr = %q, want selected profile message", errOut.String())
	}
}

func TestExchangeAuthorizationCodeReportsProviderError(t *testing.T) {
	t.Parallel()

	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if r.URL.Path != "/token" {
			t.Fatalf("path = %q, want /token", r.URL.Path)
		}
		if err := r.ParseForm(); err != nil {
			t.Fatalf("ParseForm: %v", err)
		}
		if got := r.Form.Get("grant_type"); got != "authorization_code" {
			t.Fatalf("grant_type = %q, want authorization_code", got)
		}
		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusUnauthorized)
		_, _ = w.Write([]byte(`{"error":"invalid_client","error_description":"client secret invalid"}`))
	}))
	defer srv.Close()

	_, err := exchangeAuthorizationCode(srv.URL+"/token", url.Values{
		"grant_type": {"authorization_code"},
		"code":       {"auth-code"},
		"client_id":  {"client-id"},
	})
	if err == nil {
		t.Fatalf("exchangeAuthorizationCode returned nil error")
	}
	msg := err.Error()
	if !strings.Contains(msg, "HTTP 401") || !strings.Contains(msg, "invalid_client") || !strings.Contains(msg, "client secret invalid") {
		t.Fatalf("error = %q, want status and provider error details", msg)
	}
}
